// ===== FINALE ÜBUNGEN: RESTLICHE THEMEN =====
// Kalter Krieg, Wiedervereinigung (Klasse 9)
// Russland, China, Türkei, EU (Klasse 10)

const TOPIC_EXERCISES_FINAL = {
    'kalter-krieg': [
        { id: 'kk-1', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie die beiden Hauptblöcke im Kalten Krieg und ihre führenden Mächte.', points: 2, sampleAnswer: ['Westblock: USA, NATO-Staaten', 'Ostblock: UdSSR, Warschauer Pakt'], tips: 'Zwei Blöcke, zwei Supermächte.' },
        { id: 'kk-2', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie vier Krisen des Kalten Krieges.', points: 4, sampleAnswer: ['Berlin-Blockade 1948/49', 'Koreakrieg 1950-53', 'Kubakrise 1962', 'Vietnamkrieg 1955-75'], tips: 'Stellvertreterkriege und direkte Konfrontationen.' },
        { id: 'kk-3', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie die Berlin-Blockade 1948/49.', points: 6, sampleAnswer: 'Juni 1948: Sowjets blockierten alle Zufahrtswege nach West-Berlin (Reaktion auf Währungsreform). USA organisierten Luftbrücke ("Rosinenbomber") - versorgten 2 Mio. Menschen 11 Monate lang. Mai 1949: Blockade beendet. Bedeutung: Erste große Konfrontation, stärkte Westbindung Berlins.', tips: 'Luftbrücke als Symbol westlicher Entschlossenheit.' },
        { id: 'kk-4', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie das Wettrüsten zwischen USA und UdSSR.', points: 6, sampleAnswer: 'Atomwaffen-Wettlauf: USA 1945 erste Atombombe, UdSSR 1949. Wasserstoffbomben 1950er. Interkontinentalraketen. "Gleichgewicht des Schreckens" (MAD - Mutual Assured Destruction). Beide Seiten konnten sich gegenseitig vernichten. Rüstungsausgaben belasteten Wirtschaft. Wettrüsten eskalierte bis 1980er, dann Abrüstung.', tips: 'Nukleare Abschreckung prägte die Ära.' },
        { id: 'kk-5', operator: 'zusammenfassen', afb: 1, method: 'reproduktion', question: 'Fassen Sie die Kubakrise 1962 zusammen.', points: 5, sampleAnswer: 'UdSSR stationierte Raketen auf Kuba (90 Meilen von USA). USA verhängten Seeblockade. Welt am Rand des Atomkriegs. Geheimverhandlungen Kennedy-Chruschtschow. Lösung: UdSSR entfernte Raketen, USA versprachen Kuba nicht anzugreifen (und entfernten heimlich Raketen aus Türkei). Heißer Draht installiert. Gefährlichste Krise des Kalten Krieges.', tips: 'Nächster Punkt war der Atomkrieg.' },
        { id: 'kk-6', operator: 'wiedergeben', afb: 1, method: 'reproduktion', question: 'Geben Sie die Prinzipien der Truman-Doktrin 1947 wieder.', points: 5, sampleAnswer: 'Präsident Truman: USA unterstützt freie Völker gegen kommunistische Bedrohung. Eindämmung (Containment) des Kommunismus. Hilfe für Griechenland und Türkei. Markierte Beginn des Kalten Krieges. Ideologische Konfrontation. "Verteidigung der freien Welt".', tips: 'Containment-Politik als US-Strategie.' },
        { id: 'kk-7', operator: 'skizzieren', afb: 1, method: 'reproduktion', question: 'Skizzieren Sie den Verlauf der Entspannungspolitik (Détente) 1970er.', points: 5, sampleAnswer: 'Nach Krisen: Entspannung. SALT-Verträge (Rüstungsbegrenzung). Ostverträge (Brandt). KSZE Helsinki 1975 (Menschenrechte, Grenzen). Wirtschaftliche Zusammenarbeit. Kultureller Austausch. Ende mit Afghanistan-Invasion 1979. Neue Eiszeit 1980er, dann Gorbatschow.', tips: 'Kurzfristige Entspannung zwischen Krisen.' },
        { id: 'kk-8', operator: 'erklaeren', afb: 2, method: 'transfer', question: 'Erklären Sie, warum der Kalte Krieg "kalt" blieb.', points: 7, sampleAnswer: 'Keine direkte militärische Konfrontation USA-UdSSR weil: 1) Atomwaffen - gegenseitige Vernichtung sicher. 2) Vernunft beider Seiten. 3) Abschreckung funktionierte. 4) Kommunikation (heißer Draht nach Kuba). 5) Stellvertreterkriege als Ventil. "Gleichgewicht des Schreckens" verhinderte heißen Krieg. Aber: Viele starben in Proxy-Kriegen (Korea, Vietnam).', tips: 'Atomwaffen als Friedensgarant paradoxerweise.' },
        { id: 'kk-9', operator: 'analysieren', afb: 2, method: 'bildanalyse', question: 'Analysieren Sie Churchills "Eiserner Vorhang"-Rede 1946 als Quelle.', points: 6, sampleAnswer: 'Churchill warnte: "Eiserner Vorhang" teilt Europa. Von Stettin bis Triest sowjetische Kontrolle. Aufruf an USA: Wachsam sein gegen kommunistische Expansion. Rhetorik: Dramatisch, mahnend. Kontext: Beginn des Kalten Krieges. Wirkung: Prägte Begriff "Eiserner Vorhang". Stalin reagierte empört. Historische Bedeutung: Frühe Analyse der Teilung.', tips: 'Metapher des Eisernen Vorhangs prägte die Ära.' },
        { id: 'kk-10', operator: 'einordnen', afb: 2, method: 'transfer', question: 'Ordnen Sie den Vietnamkrieg in den Kontext des Kalten Krieges ein.', points: 6, sampleAnswer: 'Stellvertreterkrieg: USA unterstützten Südvietnam (kapitalistisch), UdSSR/China Nordvietnam (kommunistisch). Domino-Theorie: USA fürchteten Ausbreitung des Kommunismus in Asien. 1965-1973 direkte US-Intervention. Scheitern: 1975 kommunistischer Sieg. Bedeutung: Zeigt Grenzen US-Macht. Anti-Kriegsbewegung in USA. Trauma für Amerika. Kalter Krieg wurde heiß in der Dritten Welt.', tips: 'Proxy-Krieg mit verheerenden Folgen.' },
        { id: 'kk-11', operator: 'vergleichen', afb: 2, method: 'transfer', question: 'Vergleichen Sie NATO und Warschauer Pakt.', points: 6, sampleAnswer: 'NATO (1949): Westliches Verteidigungsbündnis, demokratisch, USA führend, freiwillig. Warschauer Pakt (1955): Ostblock-Militärbündnis, UdSSR dominiert, erzwungen. Gemeinsamkeiten: Militärbündnisse, Abschreckung, kollektive Verteidigung. Unterschiede: NATO überlebte Kalten Krieg, Warschauer Pakt löste sich 1991 auf. NATO-Erweiterung nach Osten ist heute russisches Streitthema.', tips: 'Zwei Militärblöcke als Strukturmerkmal des Kalten Krieges.' },
        { id: 'kk-12', operator: 'herausarbeiten', afb: 2, method: 'textanalyse', question: 'Arbeiten Sie aus Kennans "Long Telegram" die Containment-Strategie heraus.', points: 6, sampleAnswer: 'George Kennan (US-Diplomat in Moskau): UdSSR expansionistisch, aber vorsichtig. Empfehlung: "Containment" - Eindämmung, nicht Rollback. Geduld, standhaft bleiben. Kommunismus werde irgendwann kollabieren. Keine Appeasement, aber auch kein Krieg. Grundlage der US-Politik 40 Jahre. Kalter Krieg als ideologischer Langzeitkonflikt.', tips: 'Strategisches Konzept für den ganzen Kalten Krieg.' },
        { id: 'kk-13', operator: 'charakterisieren', afb: 2, method: 'transfer', question: 'Charakterisieren Sie die Rolle Deutschlands im Kalten Krieg.', points: 6, sampleAnswer: 'Deutschland als Frontlinie: BRD im Westen, DDR im Osten. Berlin als Brennpunkt (Blockade, Mauer). Hochgerüstet auf beiden Seiten. Potentieller Kriegsschauplatz. Symbol der Teilung. Aber auch: Entspannung durch Ostpolitik. Wiedervereinigung 1990 = Ende des Kalten Krieges symbolisch. Deutsche Teilung spiegelte Weltspaltung.', tips: 'Geteiltes Deutschland als Mikrokosmos des Kalten Krieges.' },
        { id: 'kk-14', operator: 'erlaeutern', afb: 2, method: 'transfer', question: 'Erläutern Sie das Konzept der "Mutual Assured Destruction" (MAD).', points: 5, sampleAnswer: 'Gegenseitig zugesicherte Vernichtung: Beide Supermächte können einander vollständig zerstören. Zweitschlagfähigkeit garantiert. Folge: Atomkrieg ist irrational - beide Seiten sterben. Paradox: Atomwaffen verhindern Krieg durch Drohung der Apokalypse. "Gleichgewicht des Schreckens". Stabilität durch Terror. Abrüstung schwierig wegen Misstrauen.', tips: 'Abschreckung durch totale Vernichtungsdrohung.' },
        { id: 'kk-15', operator: 'beurteilen', afb: 3, method: 'reflexion', question: 'Beurteilen Sie: Wer trägt die Hauptverantwortung für den Kalten Krieg?', points: 8, sampleAnswer: 'Pro UdSSR-Schuld: Stalin brach Jalta-Vereinbarungen. Osteuropa wurde zwangsweise kommunistisch. Berlin-Blockade. Aggressiv-expansionistisch. Pro USA-Schuld: Atombomben-Monopol bedrohlich. Truman-Doktrin aggressiv. Umkreisung der UdSSR. Historische Debatte (Traditionalisten vs. Revisionisten vs. Post-Revisionisten): Urteil: Beide Seiten trugen bei. Strukturell war Konflikt fast unvermeidbar (Ideologie, Macht, Misstrauen). Keine Alleinschuld. Systemkonflikt plus Machtpolitik. Wichtig: Kalter Krieg war Prozess, keine einzelne Entscheidung.', tips: 'Komplexe Verantwortung, ideologisch und machtpolitisch.' },
        { id: 'kk-16', operator: 'bewerten', afb: 3, method: 'reflexion', question: 'Bewerten Sie die Kubakrise: Sieg Kennedys oder Kompromiss?', points: 8, sampleAnswer: 'Sieg-These: Kennedy zwang Chruschtschow zum Rückzug. USA demonstrierten Stärke. Kompromiss-These: Beide gaben nach (USA Türkei-Raketen, Kuba-Garantie). Gesichtswahrung für beide. Bewertung: Öffentlich schien Kennedy Sieger. Real war es Kompromiss. Wichtiger: Beide lernten - Atomkrieg muss verhindert werden. Heißer Draht, spätere Entspannung. Eigentlicher Sieg: Vernunft über Ideologie. Krise war Wendepunkt zu Rationalität.', tips: 'Öffentliche Wahrnehmung vs. diplomatische Realität.' },
        { id: 'kk-17', operator: 'eroertern', afb: 3, method: 'reflexion', question: 'Erörtern Sie: War der Kalte Krieg unvermeidbar nach 1945?', points: 8, sampleAnswer: 'These: Ja, unvermeidbar. Ideologien unvereinbar (Kapitalismus vs. Kommunismus). Machtpolitisches Vakuum in Europa. Misstrauen aus WK2 (Stalin vs. Westen). Atomwaffen schufen Sicherheitsdilemma. Antithese: Nein, vermeidbar. Alternative Entwicklungen möglich. Roosevelt war konzilianter als Truman. Kooperation in UNO anfangs. Kalter Krieg entwickelte sich graduell. Synthese: Konfliktstoffe waren da, aber Kalter Krieg war nicht determiniert. Entscheidungen (Truman-Doktrin, Berlin-Blockade) verschärften. Strukturelle Spannungen + menschliche Entscheidungen. Wahrscheinlich, aber nicht zwangsläufig.', tips: 'Struktur vs. Handlungsmacht.' },
        { id: 'kk-18', operator: 'stellung-nehmen', afb: 3, method: 'reflexion', question: 'Nehmen Sie Stellung: Waren Atomwaffen Fluch oder Segen im Kalten Krieg?', points: 7, sampleAnswer: 'Position: Paradoxerweise Segen. Begründung: Ohne Atomwaffen hätte es womöglich WK3 gegeben (konventionell). MAD verhinderte direkte Konfrontation. "Long Peace" in Europa. Kubakrise zeigte: Angst vor Vernichtung erzwingt Vernunft. Aber: Riesiges Risiko (Fehlalarm, Unfall). Wettrüsten verschwendete Ressourcen. Proxy-Kriege kosteten Millionen Leben. Fazit: Atomwaffen verhinderten großen Krieg, schufen aber permanente Bedrohung und starben Menschen in Stellvertreterkriegen. Friedensgarant mit apokalyptischem Risiko.', tips: 'Paradox der nuklearen Abschreckung.' },
        { id: 'kk-19', operator: 'diskutieren', afb: 3, method: 'reflexion', question: 'Diskutieren Sie: War die Containment-Politik erfolgreich?', points: 8, sampleAnswer: 'Position Erfolg: Kommunismus breitete sich nicht weiter aus (nach 1950ern). UdSSR kollabierte 1991. Westen "gewann" Kalten Krieg. Geduld zahlte sich aus (Kennan hatte recht). Position Misserfolg: Kommunismus kam nach China, Kuba, Vietnam. Stellvertreterkriege kosteten Millionen. Unterstützung von Diktatoren (Contra Prinzipien). Wettrüsten wirtschaftlich schädlich. Synthese: Langfristig erfolgreich (UdSSR-Kollaps), aber hoher Preis. Fraglich ob Kommunismus nur wegen Containment scheiterte (interne Probleme wichtiger?). Erfolg mit Schattenseiten.', tips: 'Langfristiger Erfolg, aber ethisch und praktisch problematisch.' },
        { id: 'kk-20', operator: 'pruefen', afb: 3, method: 'reflexion', question: 'Prüfen Sie die These: "Der Kalte Krieg war ein Dritter Weltkrieg - nur ohne direkte Kämpfe."', points: 8, sampleAnswer: 'Kriterien für Weltkrieg: Global, viele Tote, existentiell. Pro: Weltweite Dimension (Europa, Asien, Afrika, Lateinamerika). Millionen Tote in Proxy-Kriegen. Wettrüsten wie Kriegswirtschaft. Ideologischer Totalkonflikt. "Dritter" nach 1 und 2. Kontra: Keine direkte Konfrontation der Hauptmächte. Keine Kämpfe in Europa. Unterbrechungen (Entspannung). Prüfung: These hat Berechtigung. Global und existentiell. Aber: Unterschied zu WK1/2 ist "kalt". Besser formuliert: "Kalter Krieg war weltweiter Konflikt mit Weltkriegs-Dimensionen, aber ohne direkte Supermacht-Konfrontation." Hybrid zwischen Frieden und Krieg.', tips: 'Weltweite Dimension, aber anderer Charakter als WK1/2.' }
    ],

    'wiedervereinigung': [
        { id: 'wv-1', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie die Schlüsselereignisse der friedlichen Revolution 1989.', points: 4, sampleAnswer: ['Montagsdemonstrationen Leipzig', 'Fall der Berliner Mauer 9.11.1989', 'Rücktritt SED-Führung', 'Freie Volkskammerwahl 18.3.1990'], tips: 'Von Protesten zur Einheit in einem Jahr.' },
        { id: 'wv-2', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie die vier Hauptakteure der Zwei-plus-Vier-Verhandlungen.', points: 4, sampleAnswer: ['Zwei: BRD (Kohl/Genscher) und DDR', 'Vier: USA, UdSSR, Großbritannien, Frankreich'], tips: 'Deutsche plus Siegermächte regelten Einheit.' },
        { id: 'wv-3', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie den Ablauf der Montagsdemonstrationen.', points: 6, sampleAnswer: 'Ab September 1989 in Leipzig, dann andere Städte. Begann nach Friedensgebeten in Nikolaikirche. Anfangs hunderte, dann hunderttausende. Ruf: "Wir sind das Volk!" (später "Wir sind ein Volk!"). Gewaltfreiheit trotz Polizeidrohungen. 9.10.: 70.000 in Leipzig, Regime wagte keine Gewalt. Symbolisch wichtig für friedlichen Charakter der Revolution.', tips: 'Friedlicher Protest erzwang Veränderung.' },
        { id: 'wv-4', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie die Nacht des Mauerfalls 9. November 1989.', points: 6, sampleAnswer: 'SED-Funktionär Schabowski verkündete versehentlich sofortige Reisefreiheit. Massen strömten zu Grenzübergängen. Grenzer überfordert, öffneten Tore. Tausende feierten auf Mauer. Sektflaschen, Tanzen, Tränen. West-Berliner begrüßten Ossis. Historischer Moment. Mauer fiel ohne Schuss. Symbol: Ende der Teilung. "Die Mauer muss weg!" wurde real.', tips: 'Legendäre Nacht durch Missverständnis und Volksdruck.' },
        { id: 'wv-5', operator: 'zusammenfassen', afb: 1, method: 'reproduktion', question: 'Fassen Sie den Weg zur deutschen Einheit (Nov 89 - Okt 90) zusammen.', points: 6, sampleAnswer: '9.11.89: Mauerfall. 18.3.90: Erste freie DDR-Wahl (CDU gewinnt). 1.7.90: Währungsunion (D-Mark in DDR). 31.8.90: Einigungsvertrag. 12.9.90: Zwei-plus-Vier-Vertrag (äußere Einheit). 3.10.90: Beitritt DDR zur BRD. Schneller als erwartet. Kohl nutzte Gelegenheit.', tips: 'Von Mauerfall bis Einheit in nur 11 Monaten.' },
        { id: 'wv-6', operator: 'wiedergeben', afb: 1, method: 'reproduktion', question: 'Geben Sie die Hauptinhalte des Einigungsvertrags wieder.', points: 5, sampleAnswer: 'DDR tritt BRD bei (Artikel 23 GG). Grundgesetz gilt für ganz Deutschland. Hauptstadt Berlin. Übernahme westdeutschen Rechts. Angleichung der Lebensverh ältnisse (Solidarpakt). Stasi-Akten Aufarbeitung. Treuhandanstalt für Betriebe. Schutz von DDR-Beschäftigten.', tips: 'Beitritt, nicht Neugründung - rechtlich.' },
        { id: 'wv-7', operator: 'skizzieren', afb: 1, method: 'reproduktion', question: 'Skizzieren Sie die Rolle Gorbatschows bei der deutschen Einheit.', points: 5, sampleAnswer: 'Gorbatschow (Glasnost/Perestroika) ermöglichte Einheit. Verzicht auf Breschnew-Doktrin ("Sinatra-Doktrin"). Akzeptierte NATO-Mitgliedschaft des vereinten Deutschlands. Abzug sowjetischer Truppen. Ohne ihn: keine Einheit. Kohl versprach Wirtschaftshilfe. "Gorbi, Gorbi!"-Rufe in DDR. Friedensnobelpreis 1990.', tips: 'Gorbatschow als "Ermöglicher" der Einheit.' },
        { id: 'wv-8', operator: 'erklaeren', afb: 2, method: 'transfer', question: 'Erklären Sie, warum die DDR 1989 kollabierte.', points: 7, sampleAnswer: 'Mehrere Faktoren: 1) Gorbatschow - keine sowjetische Stütze mehr. 2) Wirtschaft marode. 3) Massenflucht (Ungarn öffnete Grenze). 4) Montagsdemos - Legitimationsverlust. 5) Starre SED-Führung. 6) Westmedien (Fernsehen) zeigten Alternativen. 7) Öffnung Osteuropa (Polen, Ungarn). Systeme ohne Rückhalt kollabieren schnell. DDR war Kunstprodukt des Kalten Krieges.', tips: 'Interne Schwäche plus externer Wandel.' },
        { id: 'wv-9', operator: 'analysieren', afb: 2, method: 'quellenanalyse', question: 'Analysieren Sie Kohls "10-Punkte-Programm" vom November 1989.', points: 6, sampleAnswer: 'Kohl präsentierte Stufenplan zur Einheit (ohne Abstimmung mit Partnern!). Zehn Schritte von Reiseerleichterungen bis Konföd eration. Offenließ Zeitpunkt. Intention: Initiative ergreifen, Einheit als Ziel setzen. Reaktion: Überraschung (auch Genscher!), Skepsis der Alliierten. Historische Bedeutung: Kohl trieb Einheit voran. Zeigte: BRD wollte Einheit. Beschleunigte Prozess.', tips: 'Kohls strategischer Vorstoß für Einheit.' },
        { id: 'wv-10', operator: 'einordnen', afb: 2, method: 'transfer', question: 'Ordnen Sie die deutsche Wiedervereinigung in das Ende des Kalten Krieges ein.', points: 6, sampleAnswer: 'Wiedervereinigung war Teil und Symbol des Endes. Gorbatschows Reformen ermöglichten Osteuropa-Umbrüche. Mauerfall als ikonischer Moment. Deutsche Einheit markierte Ende der Nachkriegsordnung. Parallel: Ostblock kollabierte (Polen, Tschechoslowakei, Rumänien). 1991: UdSSR-Auflösung. Deutschland als Testfall: Gewaltfreier Übergang. Einheit bewies: Kalter Krieg vorbei. Neue europäische Ordnung.', tips: 'Teil eines größeren Umbruchs in ganz Osteuropa.' },
        { id: 'wv-11', operator: 'vergleichen', afb: 2, method: 'transfer', question: 'Vergleichen Sie die Erwartungen 1990 mit der Realität der Einheit.', points: 6, sampleAnswer: 'Erwartungen: "Blühende Landschaften" (Kohl), schnelle Angleichung, Aufbruchstimmung, Einheit als Gewinn für alle. Realität: Deindustrialisierung Ost, Arbeitslosigkeit, Treuhand-Verkäufe umstritten, "Aufbau Ost" teuer, Mentalitätsunterschiede ("Mauer in den Köpfen"), Ostalgie vs. Besserwessi. Aber auch: Freiheit, Reisen, demokratische Rechte. Bilanz gemischt: Ökonomisch schwierig, politisch erfolgreich.', tips: 'Euphorie traf auf harte Realität.' },
        { id: 'wv-12', operator: 'herausarbeiten', afb: 2, method: 'textanalyse', question: 'Arbeiten Sie aus DDR-Bürgerrechtler-Forderungen ihre Vision heraus.', points: 6, sampleAnswer: 'Bürgerrechtler (Neues Forum, Bärbel Bohley): Wollten dritten Weg - demokratischen Sozialismus. Reform der DDR, nicht Anschluss an BRD. "Wir bleiben hier!" Skepsis gegenüber Kapitalismus. Volksabstimmung gefordert. Wurden von Einheitsdynamik überrollt. Enttäuschung: Revolution gekapert? Historische Ironie: Ermöglichten Freiheit, die dann Einheit brachte, die sie nicht alle wollten.', tips: 'Dritter Weg vs. Einheit - Bürgerrechtler verloren.' },
        { id: 'wv-13', operator: 'charakterisieren', afb: 2, method: 'transfer', question: 'Charakterisieren Sie die Rolle der Treuhand bei der Wiedervereinigung.', points: 6, sampleAnswer: 'Treuhandanstalt verwaltete DDR-Staatsbetriebe (8.000). Auftrag: Privatisieren oder schließen. Schnelle Privatisierung, oft an Westfirmen. Viele Betriebe geschlossen (nicht wettbewerbsfähig). Arbeitslosigkeit stieg. Umstritten: Zu schnell? Ausverkauf? Aber: Realität war DDR-Wirtschaft marode. Treuhand als Sündenbock für Transformation. Schwierige Aufgabe, kontroverse Bilanz.', tips: 'Symbol für Ost-Transformation und ihre Probleme.' },
        { id: 'wv-14', operator: 'erlaeutern', afb: 2, method: 'transfer', question: 'Erläutern Sie den Begriff "Mauer in den Köpfen".', points: 5, sampleAnswer: 'Trotz Mauerfall: Mentalitätsunterschiede Ost-West. "Ossis" vs. "Wessis". Vorurteile (Jammerossi, Besserwessi). Unterschiedliche Erfahrungen (Diktatur vs. Demokratie, Mangelwirtschaft vs. Überfluss). Sozialisationsunterschiede. Politische Präferenzen (AfD/Linke im Osten stärker). 30+ Jahre später immer noch spürbar, aber schwindet. Generationenfrage: Junge kennen Teilung nur aus Erzählungen.', tips: 'Psychologische Nachwirkungen der Teilung.' },
        { id: 'wv-15', operator: 'beurteilen', afb: 3, method: 'reflexion', question: 'Beurteilen Sie: War die Wiedervereinigung zu schnell?', points: 8, sampleAnswer: 'Pro Tempo: Historische Chance. Gorbatschow konnte gestürzt werden. Ohne Eile keine Einheit. Fluchtwelle aus DDR. Mehrheit wollte es. Kontra Tempo: Wirtschaftliche Probleme (Treuhand). Verfassungsdiskussion übergangen. DDR-Bürgerrechtler frustriert. Überstülpung statt Integration. Urteil: Politisch war Tempo richtig (Fenster schließt sich). Ökonomisch verursachte es Probleme. Aber: Langsam = Risiko des Scheiterns. Besser schnell vereinen, dann gemeinsam Probleme lösen. Alternativlos unter den Umständen.', tips: 'Historische Chance vs. soziale/ökonomische Probleme.' },
        { id: 'wv-16', operator: 'bewerten', afb: 3, method: 'reflexion', question: 'Bewerten Sie die Bilanz der deutschen Einheit nach 30+ Jahren.', points: 8, sampleAnswer: 'Positiv: Demokratie, Freiheit, Rechtsstaat für alle. Keine Mauer, keine Teilung. Wirtschaftlich: Ost aufgeholt (aber nicht ganz). Infrastruktur modernisiert. Berlin als Hauptstadt. Negativ: Ost-West-Unterschiede bleiben (Löhne, Vermögen, Mentalität). Politische Verwerfungen (Rechtsruck). Ostalgie. Traumata der Transformation. Bewertung: Insgesamt große Erfolgsgeschichte, aber mit Problemen. Politische Einheit gelungen, innere Einheit dauert länger. Deutsche sind froh über Einheit, aber Narben bleiben. Prozess, keine abgeschlossene Sache.', tips: 'Erfolg mit Schattenseiten - differenzierte Sicht.' },
        { id: 'wv-17', operator: 'eroertern', afb: 3, method: 'reflexion', question: 'Erörtern Sie: Beitritt (Artikel 23) oder Neugründung (Artikel 146)?', points: 8, sampleAnswer: 'Beitritt (real): DDR trat BRD bei. Grundgesetz übernommen. Schnell, pragmatisch. BRD-Kontinuität. Kontra: Keine gemeinsame Verfassung. Kein Volksentscheid. Anschluss, nicht Vereinigung? Neugründung (alternativ): Beide Staaten lösen sich auf, gründen neu. Gemeinsame Verfassung, Volksentscheid. Symbolisch: Gleichberechtigung. Kontra: Zeitaufwändig, riskant. Diskussion: Beitritt war pragmatisch richtig, aber symbolisch Verlierer: DDR. Besser wäre: Beitritt plus spätere Verfassungsreform. Faktisch: Beitritt unvermeidlich (DDR kollabiert, BRD stabil). Ideell: Neugründung wäre schöner gewesen.', tips: 'Pragmatismus vs. Symbolik der Einheit.' },
        { id: 'wv-18', operator: 'stellung-nehmen', afb: 3, method: 'reflexion', question: 'Nehmen Sie Stellung: Soll man DDR-Bürgerrechtlern Enttäuschung zugestehen?', points: 7, sampleAnswer: 'Position: Ja, Verständnis ist nötig. Begründung: Sie riskierten alles für Freiheit. Träumten von demokratischem Sozialismus. Wurden von Einheits-Dynamik überrollt. Ihre Vision ging unter. Fühlen sich unverstanden. Aber: Mehrheit wollte Einheit (Wahlen zeigten das). Dritter Weg war Illusion (DDR-Wirtschaft zerstört). Bürgerrechtler ermöglichten Veränderung, kontrollierten sie aber nicht. Fazit: Respekt für Mut, aber ihre Vision war unrealistisch. Enttäuschung verständlich, aber Geschichte geht eigene Wege. Ohne sie keine Einheit - ihr Verdienst bleibt.', tips: 'Helden der Revolution, aber ohne Mehrheit für ihre Vision.' },
        { id: 'wv-19', operator: 'diskutieren', afb: 3, method: 'reflexion', question: 'Diskutieren Sie: War 1989 eine Revolution?', points: 8, sampleAnswer: 'Pro Revolution: Sturz der Herrschaft (SED). Massenbewegung. Gewaltfreier Umsturz. Grundlegende Veränderung (System). "Friedliche Revolution" ist anerkannt. Kontra Revolution: Keine Gewalt. Keine Umwälzung wie 1789 oder 1917. Anschluss an bestehenden Staat (BRD), keine Neuerfindung. "Revolution von oben" (Gorbatschow ermöglichte). Diskussion: Revolution im Sinne von: Systemwechsel ja, Gewalt nein. "Friedliche Revolution" ist spezifische Form. Historisch einzigartig: Diktatur stürzt ohne Blutvergießen. Revolutionär war: Volk setzte sich durch. Konservativ war: Anschluss an Status quo ante (BRD). Synthese: Revolutionärer Prozess mit konservativem Ergebnis.', tips: 'Revolutionärer Charakter trotz Gewaltlosigkeit.' },
        { id: 'wv-20', operator: 'pruefen', afb: 3, method: 'reflexion', question: 'Prüfen Sie die These: "Die Einheit war Kohls Verdienst."', points: 8, sampleAnswer: 'Kriterien: Initiative, Diplomatie, Durchsetzung. Pro: Kohl erkannte Chance. 10-Punkte-Programm. Überzeugte Gorbatschow (Wirtschaftshilfe). Verhandelte mit Alliierten. "Kanzler der Einheit". Kontra: Ohne DDR-Bürgerrechtler keine Revolution. Ohne Gorbatschow keine Einheit. Ohne USA/Westen kein Zwei-plus-Vier. Kohl nutzte Situation, schuf sie nicht. Prüfung: Kohl war wichtig, aber nicht alleinverantwortlich. Er war richtiger Mann zur richtigen Zeit. Verdienst: Nutzte Gelegenheit entschlossen. Aber: Einheit war kollektive Leistung (DDR-Bürger, Gorbatschow, Allierte, Kohl). Besser: "Kohl trug entscheidend bei, aber Einheit war multikausales Ereignis." Personalisierung ist zu einfach.', tips: 'Individueller Beitrag vs. historische Prozesse.' }
    ],

    'russland': [
        { id: 'rus-1', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie die wichtigsten Herrscher Russlands 1894-1991.', points: 4, sampleAnswer: ['Zar Nikolaus II. (1894-1917)', 'Lenin (1917-1924)', 'Stalin (1924-1953)', 'Chruschtschow (1953-1964)', 'Breschnew (1964-1982)', 'Gorbatschow (1985-1991)'], tips: 'Von Zaren zu Kommunisten zu Reformern.' },
        { id: 'rus-2', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie die Hauptphasen der Russischen Revolution 1917.', points: 3, sampleAnswer: ['Februarrevolution: Sturz des Zaren', 'Provisorische Regierung (Februar-Oktober)', 'Oktoberrevolution: Bolschewiki-Machtübernahme'], tips: 'Zwei Revolutionen in einem Jahr.' },
        { id: 'rus-3', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie das Zarenreich unter Nikolaus II.', points: 6, sampleAnswer: 'Autokratie: Zar mit absoluter Macht. Rückständigkeit: Agrarland, wenig Industrie. Leibeigenschaft erst 1861 abgeschafft. Soziale Spannungen (Bauern, Arbeiter). Revolution 1905 erzwang Duma (Parlament), aber Zar behielt Macht. Russifizierung, Pogrome gegen Juden. Erster Weltkrieg überforderte System. Rasputin-Affäre. 1917: Zusammenbruch.', tips: 'Rückständigkeit und Repression führten zur Revolution.' },
        { id: 'rus-4', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie Stalins Terror in den 1930er Jahren.', points: 6, sampleAnswer: 'Großer Terror 1936-1938: Schauprozesse, "Säuberungen". Millionen verhaftet, hingerichtet, im Gulag. Parteigenossen, Militärs, Intellektuelle. Paranoia Stalins. NKWD (Geheimpolizei). Ziel: Absolute Kontrolle. Denunziationen. Klima der Angst. 7-20 Millionen Opfer geschätzt. Persönlichkeitskult. "Säuberung" dezimierte Elite, schwächte Militär vor WK2.', tips: 'Totalitärer Terror zur Machterhaltung.' },
        { id: 'rus-5', operator: 'zusammenfassen', afb: 1, method: 'reproduktion', question: 'Fassen Sie Gorbatschows Reformen zusammen.', points: 5, sampleAnswer: 'Glasnost (Offenheit): Meinungsfreiheit, Kritik erlaubt, Medien freier. Perestroika (Umgestaltung): Wirtschaftsreform, begrenzte Marktwirtschaft. Demokratisierung: Mehrparteiensystem, Wahlen. Außenpolitik: Abrüstung, Entspannung, Rückzug aus Afghanistan. Folgen: Unbeabsichtigt: Kontrollverlust, Osteuropa-Aufstände, UdSSR-Auflösung 1991. Gorbatschow wollte reformieren, löste aber System auf.', tips: 'Reformversuch endete mit Systemkollaps.' },
        { id: 'rus-6', operator: 'wiedergeben', afb: 1, method: 'reproduktion', question: 'Geben Sie die Ideologie der Bolschewiki wieder.', points: 5, sampleAnswer: 'Kommunismus nach Marx/Lenin. Diktatur des Proletariats. Verstaatlichung aller Produktionsmittel. Keine Privatwirtschaft. Planwirtschaft. Abschaffung von Klassen. Internationale Revolution ("Weltrevolution"). Partei als Avantgarde. Demokratischer Zentralismus. Atheismus (Religion als Opium). Ziel: Klassenlose Gesellschaft.', tips: 'Radikaler Kommunismus unter Einparteienherrschaft.' },
        { id: 'rus-7', operator: 'skizzieren', afb: 1, method: 'reproduktion', question: 'Skizzieren Sie den Verlauf des russischen Bürgerkriegs 1918-1921.', points: 5, sampleAnswer: 'Nach Oktoberrevolution: Bürgerkrieg. Rote (Bolschewiki) vs. Weiße (Zaristen, Liberale, Sozialrevolutionäre). Ausländische Intervention (Westmächte unterstützten Weiße). "Kriegskommunismus": Requirierung. Rote gewannen durch: Organisation (Trotzki), rote Armee, zentrale Lage. Weiße zerstritten. Millionen Tote (Kampf, Hunger, Terror). Ende 1921: Bolschewiki setzten sich durch.', tips: 'Brutaler Bürgerkrieg festigte Bolschewiki-Herrschaft.' },
        { id: 'rus-8', operator: 'erklaeren', afb: 2, method: 'transfer', question: 'Erklären Sie, warum das Zarenreich 1917 zusammenbrach.', points: 7, sampleAnswer: 'Strukturelle Schwächen: Rückständigkeit, soziale Spannungen, autokratisches System. Kriegsbelastung: WK1 überforderte Russland - Millionen Tote, Wirtschaft zerstört, Versorgung kollabierte. Politische Krise: Zar inkompetent, Rasputin-Skandal, kein Vertrauen. Februaraufstand: Hungerrevolten, Soldaten verweigerten Gehorsam. Zar isoliert, dankte ab. System hatte keine Reserven mehr. Krieg war Brandbeschleuniger für vorhandene Probleme.', tips: 'Strukturkrise + Kriegschaos = Revolution.' },
        { id: 'rus-9', operator: 'analysieren', afb: 2, method: 'quellenanalyse', question: 'Analysieren Sie ein sowjetisches Propagandaplakat aus den 1930ern.', points: 6, sampleAnswer: 'Typische Elemente: Heroische Arbeiter/Bauern, kraftvolle Posen. Roter Stern, Hammer & Sichel. Optimistische Zukunftsvision (Industrie, Traktoren). Stalin-Kult (oft abgebildet). Texte: Slogans ("Vorwärts zur kommunistischen Zukunft!"). Sozialistischer Realismus. Intention: Mobilisierung, Motivation, Legitimation. Verschleierung der Realität (Terror, Hunger). Kontrastiert mit Gulag-Realität. Propaganda als Herrschaftsinstrument.', tips: 'Idealisierung vs. brutale Realität.' },
        { id: 'rus-10', operator: 'einordnen', afb: 2, method: 'transfer', question: 'Ordnen Sie die NEP (Neue Ökonomische Politik) 1921 ein.', points: 6, sampleAnswer: 'Nach Bürgerkrieg: Wirtschaft zerstört, Hungersnot. Lenin führte NEP ein: Begrenzte Privatwirtschaft, Markt für Landwirtschaft, kleine Betriebe. "Staatskapitalismus". Rückzug vom reinen Kommunismus. Erholung der Wirtschaft. Umstritten in Partei (Verrat?). 1928: Stalin beendete NEP, Zwangskollektivierung. Bedeutung: Zeigt Pragmatismus Lenins. Wendepunkt: Von Revolution zu Konsolidierung.', tips: 'Pragmatischer Rückzug zur Stabilisierung.' },
        { id: 'rus-11', operator: 'vergleichen', afb: 2, method: 'transfer', question: 'Vergleichen Sie Lenin und Stalin als Herrscher.', points: 6, sampleAnswer: 'Lenin: Revolutionär, Ideologe. Gewalt (Roter Terror), aber pragmatisch (NEP). Kollektive Führung. Starb 1924. Stalin: Diktator, Machtmensch. Extremer Terror (Gulag, Säuberungen). Persönlichkeitskult. Planwirtschaft radikal. Gemeinsamkeiten: Beide Kommunisten, gewaltbereit, Einparteienherrschaft. Unterschiede: Stalin totalitärer, paranoider, mörderischer. Lenin hatte Visionen, Stalin Machterhalt. Historische Debatte: War Stalinismus Folge Leninismus oder Bruch?', tips: 'Lenin legte Grund, Stalin radikalisierte.' },
        { id: 'rus-12', operator: 'herausarbeiten', afb: 2, method: 'textanalyse', question: 'Arbeiten Sie aus Lenins "Was tun?" sein Parteikonzept heraus.', points: 6, sampleAnswer: 'Lenin: Partei als Avantgarde der Arbeiterklasse. Professionelle Revolutionäre, keine Massenbasis. Hierarchisch, diszipliniert. "Demokratischer Zentralismus": Diskussion intern, nach außen Geschlossenheit. Nicht spontane Revolution, sondern geplant. Kader-Partei, keine Massenpartei. Realität: Führte zu Diktatur der Partei über Proletariat. Grundlage des Bolschewismus.', tips: 'Elitäre Avantgarde-Partei, nicht Basisdemokratie.' },
        { id: 'rus-13', operator: 'charakterisieren', afb: 2, method: 'transfer', question: 'Charakterisieren Sie die Sowjetunion unter Breschnew ("Stagnation").', points: 6, sampleAnswer: 'Breschnew 1964-1982: Ära der Stagnation. Wirtschaft wuchs nicht mehr. Technologischer Rückstand. Rüstung überlastete. Gerontokratie (greise Führer). Korruption. Dissidenten verfolgt (Sacharow). Keine Reformen. Afghanistankrieg (1979). Äußerlich stabil, innerlich morsch. Setzte Niedergang ein, der zu Gorbatschow führte.', tips: 'Stagnierende Spätphase vor dem Kollaps.' },
        { id: 'rus-14', operator: 'erlaeutern', afb: 2, method: 'transfer', question: 'Erläutern Sie das Konzept der "Zwangskollektivierung".', points: 5, sampleAnswer: 'Stalin ab 1928: Bauern wurden in Kolchosen (Kollektivwirtschaften) gezwungen. Privater Landbesitz verboten. Ziel: Kontrolle, Industrialisierung finanzieren. Widerstand (bes. Kulaken = wohlhabende Bauern) brutal unterdrückt - Deportation, Mord. Folge: Hungersnöte (Holodomor Ukraine 1932/33, Millionen Tote). Produktivität sank. Terror auf dem Land. Trauma für Bevölkerung.', tips: 'Gewaltsame Umwälzung der Landwirtschaft mit Millionen Opfern.' },
        { id: 'rus-15', operator: 'beurteilen', afb: 3, method: 'reflexion', question: 'Beurteilen Sie: War die Oktoberrevolution unvermeidbar?', points: 8, sampleAnswer: 'Pro Unvermeidlichkeit: Zarenreich kollabiert. Provisorische Regierung schwach. Krieg weiter. Bauern/Arbeiter radikalisiert. Bolschewiki einzige mit Plan. Kontra: Mehrheit war nicht bolschewistisch. Sozialrevolutionäre stärker. Bolschewiki nutzten Putsch ("Oktober"). Andere Entwicklungen möglich (Demokratie, gemäßigter Sozialismus). Urteil: Revolution im Februar war wohl unvermeidbar. Aber Bolschewiki-Sieg im Oktober war nicht determiniert - sie nutzten Chaos geschickt. Putsch, nicht Volksbewegung. Alternative Entwicklungen waren möglich, aber unwahrscheinlicher unter Kriegschaos.', tips: 'Februarrevolution ja, Oktoberrevolution kontingent.' },
        { id: 'rus-16', operator: 'bewerten', afb: 3, method: 'reflexion', question: 'Bewerten Sie Gorbatschows historische Rolle.', points: 8, sampleAnswer: 'Positiv: Beendete Kalten Krieg friedlich. Ermöglichte deutsche Einheit. Demokratisierung (beabsichtigt). Friedensnobelpreis. Öffnung der Gesellschaft. Im Westen Held. Negativ: UdSSR kollabierte (nicht beabsichtigt). Wirtschaftsreformen scheiterten. Chaos der 1990er. In Russland unbeliebt. Verlust von Supermacht-Status. Bewertung: Historisch immens bedeutsam. Unbeabsichtigt: Beendete Sowjetunion. Wollte reparieren, zerstörte. Tragische Figur: Gute Absichten, verheerende Folgen (aus sowjetischer Sicht). Aber: Gewaltfreies Ende des Kommunismus ist Verdienst.', tips: 'Held im Westen, Versager in Russland - komplexe Figur.' },
        { id: 'rus-17', operator: 'eroertern', afb: 3, method: 'reflexion', question: 'Erörtern Sie: War Stalin notwendig für Sowjetunion?', points: 8, sampleAnswer: 'These Pro: Ohne Stalin keine Industrialisierung. Ohne Industrie kein Sieg über Hitler. Harte Hand nötig für Transformation. Realistische Alternative fehlte. These Kontra: Industrialisierung wäre auch ohne Terror möglich gewesen (vgl. andere Länder). Säuberungen schwächten Militär. Millionen Tote waren vermeidbar. Bucharins Weg (NEP+) wäre humaner. Synthese: Industrialisierung war nötig und erfolgte. Aber Stalins Methoden (Terror) waren nicht notwendig, sondern Resultat seiner Paranoia. Gegenbeispiele zeigen: Modernisierung ohne Massenmord möglich. Stalinismus war Wahl, nicht Notwendigkeit. Historische Verantwortung bleibt.', tips: 'Modernisierung ja, Terror nein - Mittel nicht Zweck.' },
        { id: 'rus-18', operator: 'stellung-nehmen', afb: 3, method: 'reflexion', question: 'Nehmen Sie Stellung: Soll man Lenin-Denkmäler abreißen?', points: 7, sampleAnswer: 'Position: Differenziert. Begründung: Lenin war Revolutionär UND Täter (Roter Terror, Bürgerkrieg). Erbe ambivalent. In Osteuropa wurden viele entfernt - Symbol der Unterdrückung. In Russland teilweise noch verehrt. Argumente Pro Abriss: Lenin legte Grund für Stalinismus. Gewalt. Erinnerung an Diktatur. Argumente Kontra: Historische Bedeutung. Kunstwerke. Erinnerungskultur braucht Diskussion, nicht Zerstörung. Meine Position: Kontextualisierung statt Zerstörung. Informationstafeln, Museen. Geschichte verstehen, nicht auslöschen. Aber: Entscheidung sollte bei ehemals Unterdrückten liegen.', tips: 'Umgang mit problematischem Erbe.' },
        { id: 'rus-19', operator: 'diskutieren', afb: 3, method: 'reflexion', question: 'Diskutieren Sie: Warum kollabierte die UdSSR 1991?', points: 8, sampleAnswer: 'Position 1 Ökonomie: Planwirtschaft ineffizient. Wettrüsten überlastete. Technologischer Rückstand. Erdölpreis-Verfall. Position 2 Nationalitäten: Vielvölkerstaat. Unabhängigkeitsbewegungen (Baltikum, Ukraine). Nicht mehr zusammenzuhalten. Position 3 Gorbatschow: Reformen liefen aus dem Ruder. Verlor Kontrolle. Glasnost zerstörte Legitimität. Position 4 Ideologie: Niemand glaubte mehr an Kommunismus. Legitimationsverlust. Synthese: Kombination aller Faktoren. Strukturell morsch (Ökonomie, Nationalitäten), Gorbatschow-Reformen als Katalysator. System war nicht reformierbar, nur ersetzbar. Kollaps war Ergebnis langfristiger Schwächen.', tips: 'Multikausal: Wirtschaft, Nationalismus, Reformen, Ideologie.' },
        { id: 'rus-20', operator: 'pruefen', afb: 3, method: 'reflexion', question: 'Prüfen Sie die These: "Der Kommunismus war ein nobles Experiment, das scheitern musste."', points: 8, sampleAnswer: 'Kriterien: Ziele, Mittel, Ergebnisse, Theorie vs. Praxis. Nobles Ziel: Klassenlose Gesellschaft, Gleichheit, Ende der Ausbeutung. Theoretisch attraktiv (Marx). Mittel: Gewalt, Diktatur, Terror. Ergebnisse: Millionen Tote, Unfreiheit, wirtschaftliches Scheitern. Prüfung: Ziele mögen nobel gewesen sein, Mittel und Ergebnisse waren katastrophal. Frage: War Scheitern unvermeidlich? Kommunismus fordert Abschaffung menschlicher Natur (Eigeninteresse, Freiheit). Planwirtschaft funktioniert nicht. Diktatur korrumpiert. Wahrscheinlich war Scheitern strukturell angelegt. Aber: Nicht determiniert - andere Formen denkbar. These ist berechtigt: Noble Idee, fatale Praxis, strukturelle Probleme führten zu Scheitern.', tips: 'Diskrepanz zwischen Theorie und Praxis.' }
    ],

    'china': [
        { id: 'cn-1', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie wichtige Epochen der chinesischen Geschichte (1800-2000).', points: 4, sampleAnswer: ['Qing-Dynastie (bis 1911)', 'Republik China (1912-1949)', 'Volksrepublik unter Mao (1949-1976)', 'Deng Xiaopings Reformen (ab 1978)'], tips: 'Vom Kaiserreich über Revolution zum Kommunismus.' },
        { id: 'cn-2', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie drei Hauptphasen unter Mao Zedong.', points: 3, sampleAnswer: ['Großer Sprung nach vorn (1958-1962) - Hungersnot', 'Kulturrevolution (1966-1976) - Chaos', 'Stabilisierung nach Maos Tod (1976)'], tips: 'Radikale Experimente mit verheerenden Folgen.' },
        { id: 'cn-3', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie die Opiumkriege und ihre Folgen.', points: 6, sampleAnswer: 'Erster Opiumkrieg (1839-42): Großbritannien erzwang Opiumhandel. China verlor, musste Hongkong abtreten, Häfen öffnen ("Ungleiche Verträge"). Zweiter Opiumkrieg (1856-60): Frankreich, GB. Weitere Zugeständnisse. Folgen: Demütigung Chinas, Schwächung der Qing-Dynastie, Beginn des "Jahrhunderts der Erniedrigung". Antiwes tliche Ressentiments.', tips: 'Westlicher Imperialismus demütigte China.' },
        { id: 'cn-4', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie die Kulturrevolution 1966-1976.', points: 6, sampleAnswer: 'Mao mobilisierte Jugend ("Rote Garden") gegen "Reaktionäre". Zerstörung alter Kultur. Intellektuelle, Lehrer, Parteikader verfolgt. Chaos, Gewalt. Schulen geschlossen. Wirtschaft litt. Personenkult um Mao ("Rotes Buch"). Nach Maos Tod (1976): Ende. Millionen litten, hunderttausende starben. Trauma für Generation.', tips: 'Mao säuberte Partei und zerstörte Ordnung.' },
        { id: 'cn-5', operator: 'zusammenfassen', afb: 1, method: 'reproduktion', question: 'Fassen Sie Deng Xiaopings Reformen ab 1978 zusammen.', points: 5, sampleAnswer: '"Sozialistische Marktwirtschaft": Privatwirtschaft erlaubt, Sonderwirtschaftszonen. "Egal ob Katze schwarz oder weiß, Hauptsache sie fängt Mäuse" (Pragmatismus). Öffnung nach außen. Wirtschaftswunder. Aber: Politisch bleibt Einparteienherrschaft. Tiananmen 1989: Demokratiebewegung niedergeschlagen. Deng: Wohlstand ohne Freiheit.', tips: 'Wirtschaftliche Öffnung bei politischer Repression.' },
        { id: 'cn-6', operator: 'wiedergeben', afb: 1, method: 'reproduktion', question: 'Geben Sie die Ideologie Mao Zedongs wieder.', points: 5, sampleAnswer: 'Maoismus = Kommunismus mit chinesischen Besonderheiten. Fokus auf Bauern (nicht Arbeiter wie Marx). Permanente Revolution nötig. Guerilla-Taktik. Voluntarismus ("Wille wichtiger als Bedingungen"). Massenmobilisierung. Personenkult. Antiintellektualismus (Intellektuelle = Reaktionäre). Praxis über Theorie. Selbstkritik.', tips: 'Bauernrevolution statt Arbeiterrevolution.' },
        { id: 'cn-7', operator: 'skizzieren', afb: 1, method: 'reproduktion', question: 'Skizzieren Sie den Langen Marsch 1934/35.', points: 5, sampleAnswer: 'Kommunisten flohen vor Nationalist en (Chiang Kai-shek). 12.000 km zu Fuß. Von Süden nach Norden. Nur 1/10 überlebte. Mao etablierte Führung. Mythos: Heldenhaft, opferreich. Propagandistisch wichtig. Zeigt Überlebenswillen der Kommunisten.', tips: 'Legendärer Rückzug als Gründungsmythos.' },
        { id: 'cn-8', operator: 'erklaeren', afb: 2, method: 'transfer', question: 'Erklären Sie, warum die Qing-Dynastie 1911 stürzte.', points: 7, sampleAnswer: 'Mehrere Ursachen: Externe Demütigung (Opiumkriege, Boxeraufstand). Wirtschaftliche Probleme. Modernisierungsversuche gescheitert. Nationalismus wuchs (Sun Yat-sen). Militärische Niederlagen (Japan 1895). Xinhai-Revolution 1911: Militär wechselte Seite. Letzter Kaiser Puyi (6 Jahre alt) dankte ab. Aber: Revolution führte nicht zu Stabilität - Warlords übernahmen. Schwäche der Dynastie war offenkundig.', tips: 'Innere Schwäche plus äußerer Druck.' },
        { id: 'cn-9', operator: 'analysieren', afb: 2, method: 'bildanalyse', question: 'Analysieren Sie ein Propaganda-Poster aus der Kulturrevolution.', points: 6, sampleAnswer: 'Typische Elemente: Mao als Sonne/Vater. Rote Garden mit "Rotem Buch". Zerstörung alter Symbole. Heldische Posen. Optimistische Farben trotz Chaos. Texte: Mao-Zitate. Intention: Mobilisierung der Jugend, Legitimation der Gewalt. Personenkult extrem. Realität (Chaos, Gewalt) verschleiert. Historisch: Zeigt totalitäre Kontrolle.', tips: 'Extrem e Propaganda verhüllte Gewalt.' },
        { id: 'cn-10', operator: 'einordnen', afb: 2, method: 'transfer', question: 'Ordnen Sie den Tiananmen-Platz-Protest 1989 historisch ein.', points: 6, sampleAnswer: 'Kontext: Dengs Reformen brachten Wohlstand, aber keine Freiheit. Studenten forderten Demokratie, Meinungsfreiheit. Inspiriert durch Osteuropa. Protest auf Tiananmen-Platz Peking, Millionen. 4.6.1989: Militär schlug nieder (Panzer). Hunderte bis tausende Tote. Danach: Repression, aber Wirtschaftsreformen weiter. Zeigt: KP toleriert keine politische Herausforderung. Wendepunkt: Ende der Hoffnung auf Demokratisierung.', tips: 'Demokratiebewegung brutal niedergeschlagen.' },
        { id: 'cn-11', operator: 'vergleichen', afb: 2, method: 'transfer', question: 'Vergleichen Sie Maos China mit Stalins Sowjetunion.', points: 6, sampleAnswer: 'Gemeinsamkeiten: Kommunistische Einparteienherrschaft, Personenkult, Terror, Massenmobilisierung, Planwirtschaft, Säuberungen. Unterschiede: Mao fokussiert Bauern, Stalin Industrie. Mao Kulturrevolution, Stalin Große Säuberung. China blieb nach Mao kommunistisch, UdSSR kollabierte. Opferzahlen: Maos Politik forderte mehr Tote (Großer Sprung: 15-45 Mio.). Beide totalitär, aber Mao chaotischer, Stalin systematischer.', tips: 'Zwei kommunistische Diktatoren mit unterschiedlichem Stil.' },
        { id: 'cn-12', operator: 'herausarbeiten', afb: 2, method: 'textanalyse', question: 'Arbeiten Sie aus Sun Yat-sens Drei Volksprinzipien seine Vision heraus.', points: 6, sampleAnswer: 'Sun Yat-sen (Vater der Nation): 1) Nationalismus - China von Ausländern befreien, Selbstbestimmung. 2) Demokratie - Volkssouveränität, Republik statt Kaiser. 3) Volkswohlfahrt - Soziale Gerechtigkeit, Landreform. Synthese westlicher und chinesischer Ideen. Problem: Praxis blieb hinter Theorie zurück. Nach Sun: Chiang und Mao interpretierten unterschiedlich. Vision blieb unerfüllt.', tips: 'Nationale, demokratische und soziale Ziele.' },
        { id: 'cn-13', operator: 'charakterisieren', afb: 2, method: 'transfer', question: 'Charakterisieren Sie das heutige China (seit Deng).', points: 6, sampleAnswer: 'Wirtschaftlich: Kapitalismus ("sozialistische Marktwirtschaft"). Zweitgrößte Volkswirtschaft. Exportmacht. Infrastruktur modern. Politisch: Einparteienherrschaft (KP), autoritär. Zensur, Überwachung. Xi Jinping Personenkult. Gesellschaftlich: Wachsender Wohlstand, Mittelschicht. Aber: Ungleichheit, Umweltprobleme. Außenpolitik: Aufstieg zur Supermacht. Belt and Road Initiative. Konflikte (Taiwan, Südchinesisches Meer). Fazit: Wirtschaftlich erfolgreich, politisch repressiv.', tips: 'Wirtschaftsliberalismus plus politische Diktatur.' },
        { id: 'cn-14', operator: 'erlaeutern', afb: 2, method: 'transfer', question: 'Erläutern Sie die Folgen des Großen Sprungs nach vorn.', points: 5, sampleAnswer: 'Mao 1958: Schnelle Industrialisierung und Kollektivierung. Volkskommunen. Unrealistische Ziele. Ergebnisse: Hungersnot 1959-1962. Geschätzt 15-45 Millionen Tote (größte Hungersnot der Geschichte). Ursachen: Fehlplanung, Lügen (lokale Kader), Ignoranz. Exportierte Getreide trotz Mangel. Mao trat zurück, blieb aber mächtig. Trauma. Zeigt Gefahren totalitärer Planung.', tips: 'Größte von Menschen gemachte Katastrophe.' },
        { id: 'cn-15', operator: 'beurteilen', afb: 3, method: 'reflexion', question: 'Beurteilen Sie Maos historische Rolle: Befreier oder Tyrann?', points: 8, sampleAnswer: 'Befreier-Sicht: Einigte China nach Jahrhundert der Erniedrigung. Beendete Warlord-Chaos. Vertrieb Japaner/Nationalisten. Gab China Stolz zurück. Landreform half Bauern. Tyrann-Sicht: Großer Sprung tötete Millionen. Kulturrevolution zerstörte Kultur/Gesellschaft. Personenkult, Diktatur. Total itärer Terror. Urteil: Ambivalent. Historisch bedeutsam, vereinte China. Aber: Preis war riesig - Millionen Tote. Modernisierung kam erst nach Mao. Mehr Tyrann als Befreier. In China offiziell: "70% gut, 30% Fehler" - verschleiert Ausmaß der Verbrechen.', tips: 'Komplexe Figur - Einiger und Massenmörder.' },
        { id: 'cn-16', operator: 'bewerten', afb: 3, method: 'reflexion', question: 'Bewerten Sie Dengs "sozialistische Marktwirtschaft".', points: 8, sampleAnswer: 'Erfolge: Wirtschaftliches Wunder, hunderte Millionen aus Armut geholt. China Weltmacht. Pragmatismus siegte. Infrastruktur, Bildung verbessert. Probleme: Ungleichheit riesig. Umweltzerstörung. Korruption. Politisch keine Freiheit (Tiananmen!). Menschenrechte verletzt. Arbeiter ausgebeutet. Bewertung: Ökonomisch erfolgreichstes Modell (schnelles Wachstum). Aber: Ohne politische Liberalisierung. Deng opferte Freiheit für Wohlstand. Nachhaltig? Spannungen wachsen (Ungleichheit, Repression). Modell ist autoritärer Kapitalismus - ethisch fragwürdig, praktisch (bisher) erfolgreich.', tips: 'Wirtschaftserfolg ohne politische Freiheit.' },
        { id: 'cn-17', operator: 'eroertern', afb: 3, method: 'reflexion', question: 'Erörtern Sie: Kann China ohne Demokratisierung stabil bleiben?', points: 8, sampleAnswer: 'These: Nein, instabil. Argument: Ohne Freiheit wächst Druck. Mittelschicht will Mitsprache. Repression erzeugt Widerstand. Korruption. Legitimation nur durch Wachstum - wenn Wirtschaft stockt? Antithese: Ja, stabil. Argument: KP hat Kontrolle (Zensur, Überwachung, Social Credit). Pragmatisch, nicht ideologisch. Wachstum schafft Legitimation. Chinesische Tradition: Ordnung wichtiger als Freiheit. Synthese: Bisher stabil, aber Zukunft unsicher. KP passt sich an (Korruptionsbekämpfung, Umweltschutz). Aber: Strukturelle Probleme (Demografie, Ungleichheit). Demokratisierung nicht zwingend, aber Liberalisierung vielleicht nötig.', tips: 'Stabilität durch Repression vs. Demokratie-Notwendigkeit.' },
        { id: 'cn-18', operator: 'stellung-nehmen', afb: 3, method: 'reflexion', question: 'Nehmen Sie Stellung: Sollte man Mao-Bilder noch zeigen (Tiananmen)?', points: 7, sampleAnswer: 'Position: Nein, aus ethischen Gründen. Begründung: Mao war Massenmörder (Millionen Tote). Symbol ehren bedeutet Verbrechen relativieren. Tiananmen-Bild legitimiert Regime. Vergleich: Stalin-Porträts in Moskau wurden entfernt. Gegenargument: Geschichte auslöschen? Mao ist Teil Chinas. Verbot wäre auch Diktatur. Meine Position: Kontextualisierung statt Verehrung. Mao gehört in Museum mit kritischer Analyse, nicht als heroisches Symbol auf Platz. Aber: Entscheidung liegt bei Chinesen. Westen sollte nicht diktieren. Fakt ist: Bild bleibt zeigt autoritären Charakter Chinas.', tips: 'Umgang mit Diktator-Erbe.' },
        { id: 'cn-19', operator: 'diskutieren', afb: 3, method: 'reflexion', question: 'Diskutieren Sie: Ist China ein imperialistisches Land heute?', points: 8, sampleAnswer: 'Position Ja: Belt and Road - wirtschaftliche Dominanz. Schuldenfallen-Diplomatie. Südchinesisches Meer - militärische Expansion. Xinjiang, Tibet - Unterdrückung. Handelspraktiken aggressiv. Position Nein: Investitionen, keine militärische Eroberung. Entwicklungshilfe. Selbst Opfer westlichen Imperialismus. Defensive Interessen. Diskussion: Unterscheidet sich vom klassischen Imperialismus (keine Kolonien), aber neuer Stil: Wirtschaftliche Hegemonie. "Schuldenfalle" umstritten. Sicherlich: Großmacht mit Großmachtinteressen. Imperialistisch? Definitionsfrage. Aber: Dominanzstreben unverkennbar.', tips: 'Neuer Imperialismus oder nur Großmachtverhalten?' },
        { id: 'cn-20', operator: 'pruefen', afb: 3, method: 'reflexion', question: 'Prüfen Sie die These: "Chinas Aufstieg ist das wichtigste Ereignis des 21. Jahrhunderts."', points: 8, sampleAnswer: 'Kriterien: Global, langfristig, fundamental. Pro: China 1,4 Mrd. Menschen. Zweitgrößte Wirtschaft (bald größte?). Geopolitischer Machtwechsel (USA-China). Technologie-Konkurrenz. Neue Weltordnung. Klima: China entscheidend. Kontra: Andere Ereignisse wichtig (Klimawandel, Digitalisierung, Migration). China aufstieg begann 20. Jh. (Deng). Ob nachhaltig? Prüfung: These ist stark übertrieben, aber berechtigt. Chinas Aufstieg ist eines der wichtigsten Ereignisse. Aber nicht das einzige (Klimawandel evtl. wichtiger). Besser: "Chinas Aufstieg zur Supermacht ist eines der prägendsten Entwicklungen des frühen 21. Jh." Definitorisch wichtig.', tips: 'Geopolitischer Machtwechsel mit globaler Bedeutung.' }
    ],

    'tuerkei-osmanisches-reich': [
        { id: 'ot-1', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie die Phasen der türkischen/osmanischen Geschichte 1800-1950.', points: 4, sampleAnswer: ['Osmanisches Reich (bis 1922)', 'Jungtürken-Bewegung (1908)', 'Völkermord an Armeniern (1915)', 'Gründung Republik Türkei (1923)', 'Atatürk-Reformen (1923-1938)'], tips: 'Von Vielvölkerreich zu Nationalstaat.' },
        { id: 'ot-2', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie drei Prinzipien des Kemalismus.', points: 3, sampleAnswer: ['Laizismus (Trennung Staat/Religion)', 'Nationalismus (Türkischer Nationalstaat)', 'Modernisierung/Verwestlichung'], tips: 'Säkular, national, modern.' },
        { id: 'ot-3', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie den Niedergang des Osmanischen Reichs im 19. Jahrhundert.', points: 6, sampleAnswer: '"Kranker Mann am Bosporus": Militärische Niederlagen (Russland, Balkan). Gebietsverluste (Griechenland, Balkan, Nordafrika). Wirtschaftlich rückständig. Nationalitätenkonflikte (Serben, Bulgaren, Griechen). Tanzimat-Reformen scheiterten. Jungtürken versuchten Modernisierung. 1914: Bündnis mit Deutschland, WK1-Niederlage besiegelte Ende.', tips: 'Vielv ölkerreich kollabierte unter Nationalismen.' },
        { id: 'ot-4', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie Atatürks Reformen in den 1920er/30er Jahren.', points: 6, sampleAnswer: 'Laizismus: Kalifat abgeschafft, Scharia durch weltliches Recht ersetzt. Kleiderreform: Verbot von Fes, westliche Kleidung. Alphabet: Lateinische statt arabische Schrift. Frauenrechte: Wahlrecht, Bildung. Wirtschaft: Industrialisierung. Namensgesetz: "Atatürk" (Vater der Türken). Ziel: Moderne, westliche, säkulare Nation. Autoritär durchgesetzt.', tips: 'Radikale Modernisierung und Säkularisierung.' },
        { id: 'ot-5', operator: 'zusammenfassen', afb: 1, method: 'reproduktion', question: 'Fassen Sie den Völkermord an den Armeniern 1915 zusammen.', points: 5, sampleAnswer: '1915 während WK1: Osmanische Regierung deportierte und ermordete systematisch Armenier. Todesm ärsche in syrische Wüste. Schätzung: 1-1,5 Mio. Tote. Begründung: Angebliche Kollaboration mit Russland. Realität: Genozid aus Nationalismus. International anerkannt (außer Türkei). Türkei bestreitet bis heute Völkermord. Historisch-politisch umstritten.', tips: 'Erster Genozid des 20. Jahrhunderts.' },
        { id: 'ot-6', operator: 'wiedergeben', afb: 1, method: 'reproduktion', question: 'Geben Sie die Gründe für die Gründung der Republik Türkei wieder.', points: 5, sampleAnswer: 'Nach WK1: Osmanisches Reich verlor, sollte aufgeteilt werden (Vertrag von Sèvres). Mustafa Kemal führte Befreiungskrieg gegen Griechen und Alliierte. Sieg 1922. Vertrag von Lausanne 1923: Anerkennung der Türkei. Sultanat/Kalifat abgeschafft. Republik ausgerufen. Ankara neue Hauptstadt. Türkische Nation auf türkischem Kerngebiet. Ende des Vielvölkerreichs.', tips: 'Befreiungskrieg führte zu Nationalstaat.' },
        { id: 'ot-7', operator: 'skizzieren', afb: 1, method: 'reproduktion', question: 'Skizzieren Sie die Rolle der Jungtürken.', points: 5, sampleAnswer: 'Revolution 1908: Jungtürken zwangen Sultan zur Verfassung. Wollten Osmanisches Reich modernisieren und retten. Nationalism us. 1913: Putsch, kontrollierten Regierung. WK1: Brachten Osmanisches Reich auf Seite Deutschlands. Radikale Türkisierung. Völkermord an Armeniern. 1918: Niederlage, flohen. Wegbereiter des türkischen Nationalismus.', tips: 'Reformisten wurden zu Radikalen.' },
        { id: 'ot-8', operator: 'erklaeren', afb: 2, method: 'transfer', question: 'Erklären Sie, warum das Osmanische Reich im WK1 zusammenbrach.', points: 7, sampleAnswer: 'Strukturell schwach: Niedergang seit Jahrzehnten. Militärisch veraltet. Wirtschaftlich rückständig. Nationalitätenkonflikte (Araber, Armenier, Kurden). WK1: Bündnis mit Deutschland. Mehrere Fronten (Gallipoli, Kaukasus, Mesopotamien). Arabischer Aufstand (Lawrence von Arabien). Niederlage 1918. Besetzung durch Alliierte. Aufteilungspläne. Nur Befreiungskrieg Atatürks rettete türkisches Kerngebiet. Vielvölkerreich war nicht mehr lebensfähig.', tips: 'Innere Schwäche plus Kriegsniederlage.' },
        { id: 'ot-9', operator: 'analysieren', afb: 2, method: 'quellenanalyse', question: 'Analysieren Sie ein Foto von Atatürk in westlichem Anzug als historische Quelle.', points: 6, sampleAnswer: 'Atatürk trägt Anzug, kein Fes. Symbolik: Bruch mit osmanischer Tradition. Verwestlichung als Programm. Moderne, säkulare Türkei. Für fotografische Verbreitung inszeniert. Propaganda-Wert: Neue Türkei ist europäisch. Kontakt: Autoritäre Modernisierung. Wirkung: Vorbild für Elite. Kontrovers: Aufgezwungene Verwestlichung? Historische Bedeutung: Zeigt radikale Neuausrichtung. Personen kult Atatürks.', tips: 'Kleidung als Symbol politischer Transformation.' },
        { id: 'ot-10', operator: 'einordnen', afb: 2, method: 'transfer', question: 'Ordnen Sie den Völkermord an den Armeniern in den Kontext des Weltkriegs ein.', points: 6, sampleAnswer: 'WK1-Kontext: Osmanisches Reich kämpfte gegen Russland. Armenier lebten in Grenzgebiet. Verdacht der Kollaboration (teils gerechtfertigt: Armenische Freiwillige). Jungtürken nutzten Krieg als Deckmantel für Völkermord. Deportationsbefehl 1915. Krieg ermöglichte: Aufmerksamkeit anderswo, nationale Leidenschaft, Sündenbock. Parallele: Andere Genozide oft in Kriegen (Holocaust). Aber: Genozid war nicht Kriegshandlung, sondern systematische Vernichtung.', tips: 'Krieg als Gelegenheit für Völkermord.' },
        { id: 'ot-11', operator: 'vergleichen', afb: 2, method: 'transfer', question: 'Vergleichen Sie Atatürks Reformen mit Peters des Großen Reformen in Russland.', points: 6, sampleAnswer: 'Gemeinsamkeiten: Radikale Verwestlichung, autoritär durchgesetzt. Säkularisierung. Kleiderreformen. Alphabet (Peter nicht, aber Kalenderreform). Modernisierung von oben. Ziel: Aufholen mit Westen. Unterschiede: Zeitraum (Peter 18. Jh., Atatürk 20. Jh.). Peter behielt Monarchie, Atatürk schuf Republik. Atatürk ging weiter (Laizismus). Beide: Transformer ihrer Nationen, autoritär, umstritten.', tips: 'Aufgeklärte Despoten der Modernisierung.' },
        { id: 'ot-12', operator: 'herausarbeiten', afb: 2, method: 'textanalyse', question: 'Arbeiten Sie aus Atatürks Reden sein Nationsverständnis heraus.', points: 6, sampleAnswer: 'Türkischer Nationalismus: Nicht osmanisches Vielvölkerreich, sondern türkischer Nationalstaat. "Ne mutlu Türküm diyene" (Glücklich ist, wer sagt: Ich bin Türke). Inklusion: Wer sich als Türke fühlt, ist Türke (ethnisch definiert, aber auch zivil). Modernisierung: Türken als fortschrittliche Nation. Laizismus: Staat über Religion. Vorbild Westen. Problem: Minderheiten (Kurden, Armenier) ausgeschlossen oder assimiliert. Homogenisierung.', tips: 'Ethnisch-nationaler, aber auch ziviler Nationalismus.' },
        { id: 'ot-13', operator: 'charakterisieren', afb: 2, method: 'transfer', question: 'Charakterisieren Sie den Kemalismus als Ideologie.', points: 6, sampleAnswer: 'Sechs Pfeile: 1) Republikanismus. 2) Nationalismus (türkisch). 3) Laizismus (Säkularismus). 4) Populismus (Volksherrschaft). 5) Etatismus (Staat lenkt Wirtschaft). 6) Revolutionismus (ständige Reform). Autoritär-modernisierend. Vorbild Westen, aber eigenständig. Militär als Hüter. Personen kult um Atatürk. Bis heute Staatsdoktrin (offiziell). Umstritten: Autoritär, homogenisierend. Aber: Modernisierte Türkei.', tips: 'Autoritäre Modernisierung nach westlichem Vorbild.' },
        { id: 'ot-14', operator: 'erlaeutern', afb: 2, method: 'transfer', question: 'Erläutern Sie den Begriff "Laizismus" im türkischen Kontext.', points: 5, sampleAnswer: 'Laizismus = Radikale Trennung von Staat und Religion. Anders als Säkularismus (Religion privat): Staat kontrolliert Religion. Kalifat abgeschafft (1924). Scharia durch Zivilrecht ersetzt. Religiöse Schulen geschlossen. Orden verboten. Kleidung säkularisiert. Ziel: Religion aus öffentlichem Raum. Staat über Religion. Unterschied zum Westen: Nicht Neutralität, sondern Kontrolle. Umstritten: Legitim oder Repression?', tips: 'Strikte Säkularisierung unter staatlicher Kontrolle.' },
        { id: 'ot-15', operator: 'beurteilen', afb: 3, method: 'reflexion', question: 'Beurteilen Sie: War Atatürks autoritäre Modernisierung gerechtfertigt?', points: 8, sampleAnswer: 'Pro: Türkei war rückständig, Religion dominierte. Demokratische Transformation unwahrscheinlich. Schnelle Modernisierung nötig. Ergebnis: Moderne, stabile Türkei. Erfolg gibt Recht. Kontra: Autoritarismus, Zwang. Minderheiten unterdrückt. Demokratie geopfert. Menschenrechte verletzt. "Ziel heiligt Mittel nicht". Urteil: Resultate (Modernisierung) waren positiv. Aber Methoden (Repression) fragwürdig. Alternative: Hätte Demokratisierung funktioniert? Vermutlich nicht unter damaligen Bedingungen. Pragmatisch erfolgreich, ethisch problematisch. Kontextabhängig: Damals anders zu beurteilen als heute. Historisch verständlich, aber nicht uneingeschränkt legitimierbar.', tips: 'Zweck (Modernisierung) vs. Mittel (Autorität).' },
        { id: 'ot-16', operator: 'bewerten', afb: 3, method: 'reflexion', question: 'Bewerten Sie die türkische Haltung zum Armenier-Genozid.', points: 8, sampleAnswer: 'Türkei leugnet Genozid. Argumente: Kriegshandlung, beidseitige Gewalt, Opferzahlen übertrieben. Realität: Historisch ist Genozid belegt (Dokumente, Zeugen). International anerkannt (außer Türkei, Aserbaidschan). Bewertung: Leugnung ist 1) Historisch falsch. 2) Ethisch verwerflich - beleidigt Opfer. 3) Politisch schädlich - isoliert Türkei. 4) Psychologisch verständlich: Nationalstolz, Gründungsmythos. Türkei müsste Schuld eingestehen - schwierig. Armenier fordern Anerkennung. Vergleich Deutschland: Aufarbeitung stärkte, nicht schwächte. Türkei sollte anerkennen, aber politisch heikel. Wandel nötig für Versöhnung.', tips: 'Historische Wahrheit vs. politische Rücksicht.' },
        { id: 'ot-17', operator: 'eroertern', afb: 3, method: 'reflexion', question: 'Erörtern Sie: Ist der Kemalismus mit Demokratie vereinbar?', points: 8, sampleAnswer: 'These: Nein. Argument: Kemalismus ist autoritär. Militär als Hüter interveniert (Putsche 1960, 1971, 1980, 1997). Laizismus erzwungen. Minderheiten unterdrückt. Demokratie nur Fassade. Antithese: Ja. Argument: Republikanismus und Populismus sind demokratisch. Mehrparteiensystem ab 1950. Kemalismus als Rahmen, innerhalb dessen Demokratie. Laizismus schützt Demokratie vor Islamismus. Synthese: Ursprünglich war Kemalismus autoritär. Aber: Entwickelte sich. Demokratie möglich innerhalb kemalistischer Prinzipien (Laizismus, Republik). Spannung bleibt: Militär vs. Volk. Aktuelle Türkei (Erdoğan) zeigt: Kemalismus erodiert, Demokratie auch. Beides fragil.', tips: 'Autoritäre Gründung vs. demokratische Entwicklung.' },
        { id: 'ot-18', operator: 'stellung-nehmen', afb: 3, method: 'reflexion', question: 'Nehmen Sie Stellung: Soll man Atatürk-Denkmäler kritisch kontextualisieren?', points: 7, sampleAnswer: 'Position: Ja, Kontextualisierung nötig. Begründung: Atatürk wird verehrt (Beleidigung verboten!). Aber: Auch autoritär, Minderheiten unterdrückt. Mythos vs. Realität. Demokratische Gesellschaft sollte Gründerfiguren kritisch sehen dürfen. Informationstafeln: Verdienste (Modernisierung) UND Probleme (Repression). Aber: In Türkei politisch explosiv. Kemalist en sehen Kritik als Angriff. Gefahr: Instrumentalisierung durch Erdoğan. Meine Position: Kritische Geschichtsschreibung ist nötig. Atatürk war bedeutend, aber nicht perfekt. Balance: Respekt ohne Vergötzung. Aber: Wandel muss aus Türkei kommen, nicht von außen diktiert.', tips: 'Gründungsmythos vs. historische Differenzierung.' },
        { id: 'ot-19', operator: 'diskutieren', afb: 3, method: 'reflexion', question: 'Diskutieren Sie: War die Gründung der Türkei ein Erfolg oder Versagen?', points: 8, sampleAnswer: 'Position Erfolg: Rettete türkisches Kerngebiet vor Aufteilung. Moderne, säkulare Republik. Atatürks Reformen. Stabilität (relativ). NATO-Mitglied. Position Versagen: Osmanisches Reich verloren (nicht gerettet). Minderheiten vertrieben/unterdrückt (Armenier, Griechen, Kurden). Autoritarismus. Demokratie brüchig. Synthese: Kommt auf Perspektive an. Für Türken: Erfolg (Staat überlebte, modernisierte). Für Minderheiten: Versagen (Genozid, Vertreibung). Historisch: Türkei wurde solider Staat, aber auf Kosten anderer. Genozid macht Gründung moralisch problematisch. Erfolg und Schuld koexistieren.', tips: 'Erfolg für wen? Perspektivfrage.' },
        { id: 'ot-20', operator: 'pruefen', afb: 3, method: 'reflexion', question: 'Prüfen Sie die These: "Die Türkei ist die Brücke zwischen Ost und West."', points: 8, sampleAnswer: 'Kriterien: Geographie, Kultur, Politik, Wirtschaft. Pro: Geographisch zwischen Europa und Asien. Kulturell: Osmanisches Erbe (Orient) + Atatürks Verwestlichung. NATO-Mitglied, EU-Beitrittskandidat. Wirtschaftlich vernetzt. Migrati onsbrücke. Kontra: Politisch nicht vermittelnd, sondern zerrissen. Erdoğan-Regime autoritär. Kulturell: Weder Fisch noch Fleisch? Identitätskrise. Konflikte mit West und Ost. Prüfung: These ist geographisch-kulturell teilweise zutreffend. Aber politisch überholt. Türkei ist eher Konfliktzone als Brücke. Brücken verbinden - Türkei spaltet (intern und extern). Metapher war passender in Atatürks Zeit. Heute: Zerrissenes Land. Besser: "Türkei zwischen Welten, auf Identitätssuche."', tips: 'Schöne Metapher, aber komplizierte Realität.' }
    ],

    'europaeische-union': [
        { id: 'eu-1', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie die wichtigsten Stationen der europäischen Integration.', points: 5, sampleAnswer: ['Montanunion (EGKS) 1951', 'Römische Verträge 1957 (EWG)', 'EU-Gründung 1993 (Maastricht)', 'Osterweiterung 2004', 'Lissabon-Vertrag 2009'], tips: 'Von Kohle/Stahl zu politischer Union.' },
        { id: 'eu-2', operator: 'nennen', afb: 1, method: 'reproduktion', question: 'Nennen Sie drei Hauptorgane der EU.', points: 3, sampleAnswer: ['Europäische Kommission (Exekutive)', 'Europäisches Parlament (Gewählte Volksvertretung)', 'Europäischer Rat (Staats-/Regierungschefs)'], tips: 'Komplexes System mehrerer Institutionen.' },
        { id: 'eu-3', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie die Gründung der Montanunion 1951.', points: 6, sampleAnswer: 'Nach WK2: Frankreich, Deutschland, Italien, Benelux gründeten Europäische Gemeinschaft für Kohle und Stahl (EGKS). Ziel: Kriegswichtige Industrien gemeinsam verwalten → Krieg unmöglich machen. "Schuman-Plan" (Franz. Außenminister). Beginn der Integration. Supranationale Behörde. Erfolg führte zu weiterer Integration (EWG).', tips: 'Wirtschaftliche Integration für politischen Frieden.' },
        { id: 'eu-4', operator: 'beschreiben', afb: 1, method: 'reproduktion', question: 'Beschreiben Sie den Maastricht-Vertrag 1992.', points: 6, sampleAnswer: 'Gründete Europäische Union (aus EG). Drei Säulen: 1) EG (Wirtschaft), 2) Gemeinsame Außenpolitik, 3) Justiz/Inneres. Euro eingeführt. EU-Bürgerschaft. Subsidiaritätsprinzip. Vorbereitung Ost-Erweiterung. Von Wirtschaftsgemeinschaft zu politischer Union. Umstritten in Referenden (Dänemark, Frankreich knapp Ja). Meilenstein der Integration.', tips: 'Von EG zu EU - politische Vertiefung.' },
        { id: 'eu-5', operator: 'zusammenfassen', afb: 1, method: 'reproduktion', question: 'Fassen Sie die Osterweiterung 2004 zusammen.', points: 5, sampleAnswer: '2004: 10 neue Mitglieder (Polen, Tschechien, Ungarn, Baltikum, etc.). Größte Erweiterung. Ziel: Osteuropa nach Kaltem Krieg integrieren, Demokratie festigen. Herausforderungen: Wirtschaftsgefälle, Arbeitsmigration, unterschiedliche politische Kulturen. Beitritt als Belohnung für Transformation. Erfolg: Frieden, Wohlstand, Demokratie in Osteuropa. Aber: Auch Spannungen (Migration, Werte).', tips: 'Historische Erweiterung nach Kaltem Krieg.' },
        { id: 'eu-6', operator: 'wiedergeben', afb: 1, method: 'reproduktion', question: 'Geben Sie die Grundfreiheiten des EU-Binnenmarktes wieder.', points: 4, sampleAnswer: ['Freier Warenverkehr', 'Freier Personenverkehr', 'Freier Dienstleistungsverkehr', 'Freier Kapitalverkehr'], tips: 'Vier Freiheiten des Binnenmarkts.' },
        { id: 'eu-7', operator: 'skizzieren', afb: 1, method: 'reproduktion', question: 'Skizzieren Sie die Entstehung des Euro.', points: 5, sampleAnswer: 'Maastricht 1992: Beschluss einer Währungsunion. Konvergenzkriterien (Inflation, Schulden, Defizit). 1999: Euro als Buchgeld. 2002: Euro-Bargeld. 19 Mitglieder (Eurozone). Ziel: Wirtschaftliche Integration, Erleichterung von Handel. Probleme: Schuldenkrise 2010 (Griechenland). EZB als Zentralbank. Umstritten: Verlust nationaler Geldpolitik.', tips: 'Gemeinsame Währung als Integrationsprojekt.' },
        { id: 'eu-8', operator: 'erklaeren', afb: 2, method: 'transfer', question: 'Erklären Sie, warum die EU gegründet wurde (Motive).', points: 7, sampleAnswer: 'Hauptmotiv: Frieden. Nach zwei Weltkriegen Europa vereinen, Krieg unmöglich machen (Montanunion). Wirtschaftliche Motive: Großer Binnenmarkt, Wettbewerbsfähigkeit gegenüber USA. Politische Motive: Europa Gewicht in der Welt geben, Demokratie stabilisieren. Kulturelle Motive: Gemeinsame Werte, Zivilisation. Funktionale Integration: Zusammenarbeit in einem Bereich (Kohle/Stahl) führt zu weiterer Integration (Spill-over). EU ist Friedensprojekt geworden Wirtschaftsmacht.', tips: 'Frieden als Kern, Wirtschaft als Motor.' },
        { id: 'eu-9', operator: 'analysieren', afb: 2, method: 'quellenanalyse', question: 'Analysieren Sie Schumans Erklärung vom 9. Mai 1950.', points: 6, sampleAnswer: 'Schuman: Kohle/Stahl-Produktion unter gemeinsame Autorität. Macht Krieg nicht nur undenkbar, sondern materiell unmöglich. Erster Schritt zu europäischem Bundesstaat. Rhetorik: Versöhnung Deutschland-Frankreich. Vision: Föderales Europa. Historischer Kontext: 5 Jahre nach WK2. Intention: Frieden durch Verflechtung. Wirkung: Beginn der Integration. "Geburtsurkunde der EU". Realismus: Wirtschaftliche Integration als Grundlage. Idealismus: Friedensvision.', tips: 'Gründungsdokument der EU-Integration.' },
        { id: 'eu-10', operator: 'einordnen', afb: 2, method: 'transfer', question: 'Ordnen Sie die Eurokrise 2010ff. in die EU-Geschichte ein.', points: 6, sampleAnswer: 'Kontext: Euro 1999/2002 eingeführt. 2008: Finanzkrise. 2010: Griechenlands Schulden offenbar. Gefahr: Staatsbankrott, Euro-Zerfall. Rettungsschirme (ESM). Austerität in Südeuropa. Spannungen Nord-Süd. Bedeutung: Erste existenzielle Krise des Euro. Zeigte: Währungsunion ohne Fiskalunion problematisch. Solidarität vs. Eigeninteresse. Überwunden, aber Narben bleiben. Lehre: EU braucht tiefere Integration oder Rückbau.', tips: 'Strukturkrise der Währungsunion.' },
        { id: 'eu-11', operator: 'vergleichen', afb: 2, method: 'transfer', question: 'Vergleichen Sie die EU mit den USA als föderale Systeme.', points: 6, sampleAnswer: 'Gemeinsamkeiten: Bundesstaaten, gemeinsame Institutionen, Binnenmarkt, gemeinsame Außenpolitik (teils). Unterschiede: USA: Ein Staat, Bundesregierung stark, Englisch, 1787 gegründet. EU: Staatenbund, Mitgliedstaaten stärker, viele Sprachen, schrittweise seit 1951. USA: Volk wählt Präsident. EU: Kommissionspräsident indirekt. USA zentraler, EU dezentraler. EU zwischen Staatenbund und Bundesstaat ("sui generis"). USA sind Vorbild, aber EU ist einzigartig.', tips: 'EU ist föderaler, aber kein Bundesstaat wie USA.' },
        { id: 'eu-12', operator: 'herausarbeiten', afb: 2, method: 'textanalyse', question: 'Arbeiten Sie aus EU-Verträgen das Subsidiaritätsprinzip heraus.', points: 6, sampleAnswer: 'Subsidiaritätsprinzip: EU handelt nur, wenn Ziele auf EU-Ebene besser erreichbar als national. "Was die kleinere Einheit kann, soll sie tun." Schutz nationaler Souveränität. Verhindert Zentralisierung. In Maastricht verankert. Aber: Auslegungsfrage. Was ist "besser"? Konflikt: EU-Integration vs. nationale Kompetenz. Kritiker: Wird verletzt. Befürworter: Schützt föderales System. Wichtig für EU-Akzeptanz.', tips: 'Dezentralisierungsprinzip als Balance.' },
        { id: 'eu-13', operator: 'charakterisieren', afb: 2, method: 'transfer', question: 'Charakterisieren Sie das Demokratiedefizit der EU.', points: 6, sampleAnswer: 'Kritik: Kommission nicht direkt gewählt. Europäisches Parlament schwächer als nationale. Entscheidungen intransparent ("Brüsseler Bürokratie"). Bürger fühlen sich nicht repräsentiert. "Technokratie statt Demokratie". Gegenargumente: Parlament wurde gestärkt. Mitgliedstaaten sind demokratisch. Mehrfache Legitimation (national + europäisch). Komplexität ist Preis für Vielfalt. Debatte dauert an. Reformen nötig.', tips: 'Spannungsfeld zwischen Effizienz und Demokratie.' },
        { id: 'eu-14', operator: 'erlaeutern', afb: 2, method: 'transfer', question: 'Erläutern Sie den Brexit und seine Folgen.', points: 5, sampleAnswer: 'Brexit = Austritt Großbritanniens aus EU. Referendum 2016: 52% für Austritt. Gründe: Souveränität, Migration, EU-Skepsis. 2020: Austritt vollzogen. Folgen: Für UK: Handelshemmnisse, Schottland-Frage, Nordirland-Problem. Für EU: Verlust eines großen Mitglieds, aber auch Erleichterung (Bremser weg). Zeigt: EU-Ausstieg möglich, aber schmerzhaft. Symbol für EU-Krise.', tips: 'Historischer Präzedenzfall für EU-Ausstieg.' },
        { id: 'eu-15', operator: 'beurteilen', afb: 3, method: 'reflexion', question: 'Beurteilen Sie: War die Euro-Einführung ein Fehler?', points: 8, sampleAnswer: 'Pro Euro: Erleichtert Handel, Reisen. Schutz vor Spekulation. Symbol der Einheit. Makroökonomisch sinnvoll. Kontra: Ohne Fiskalunion problematisch. Keine gemeinsame Wirtschaftspolitik. Südeuropa litt (Austerität). Nationale Handlungsfähigkeit verloren. Urteil: Wirtschaftlich war Euro riskant ohne Fiskalunion. Eurokrise zeigte Probleme. Aber: Bis her überlebt. Für Handel/Integration positiv. Politisch war es Wagnis. Fehler: Zu früh und zu umfassend. Besser wäre: Langsamer, mit tieferer Integration. Aber: Keine Katastrophe. Ambivalent.', tips: 'Wirtschaftliche Risiken vs. politische Integration.' },
        { id: 'eu-16', operator: 'bewerten', afb: 3, method: 'reflexion', question: 'Bewerten Sie die Bilanz der EU: Erfolg oder Krise?', points: 8, sampleAnswer: 'Erfolge: 70+ Jahre Frieden. Wohlstand. Binnenmarkt. Demokratie in Osteuropa gefestigt. Größte Wirtschaftsmacht. Freiheit (Schengen). Krisen: Brexit, Euro-Krise, Migrationskrise, Ungarn/Polen (Rechtsstaatlichkeit), Covid-Koordination schwach. Bewertung: Historisch riesiger Erfolg (Frieden!). Aber: Aktuell in schwieriger Phase. Legitimationsprobleme, Akzeptanz sinkt. Balance: Erfolgsgeschichte mit aktuellen Herausforderungen. Nicht scheitern d, aber reformbedürftig. Einzigartiges Projekt, fragil.', tips: 'Langfristig erfolgreich, aktuell Probleme.' },
        { id: 'eu-17', operator: 'eroertern', afb: 3, method: 'reflexion', question: 'Erörtern Sie: Braucht die EU mehr Integration oder weniger?', points: 8, sampleAnswer: 'These Mehr: Probleme (Klima, Migration, Außenpolitik) nur gemeinsam lösbar. Eurokrise zeigt: Halbe Integration funktioniert nicht. Föderale EU (Vereinigte Staaten von Europa). Antithese Weniger: EU überdehnt. Bürger wollen Souveränität zurück. Subsidiaritätsprinzip verletzt. Rückbau auf Kerneuropa oder Binnenmarkt. Synthese: Differenzierte Integration. Kerngruppe tiefer (Eurozone), Peripherie lockerer. Oder: Mehr Demokratie statt mehr Zentralisierung. Debatte zeigt: EU an Scheideweg. Richtung unklar. Kompromiss: Integration in manchen Bereichen (Außenpolitik), Rückzug in anderen (Detailregulierung).', tips: 'Föderalismus vs. Renationalisierung.' },
        { id: 'eu-18', operator: 'stellung-nehmen', afb: 3, method: 'reflexion', question: 'Nehmen Sie Stellung: Sollten EU-Verträge in Volksabstimmungen entschieden werden?', points: 7, sampleAnswer: 'Position: Ja, mehr direkte Demokratie. Begründung: EU-Entscheidungen sind fundamental. Bürger sollten mitentscheiden. Erhöht Legitimität. Aber: Gegenargumente: Referenden scheitern oft (Frankreich/Niederlande 2005, Irland). Komplexe Verträge schwer verständlich. Populisten instrumentalisieren. Elite-Projekte scheitern an Volk. Meine Position: Prinzipiell ja, aber: Referenden brauchen Debatte, Bildung. Nicht ja/nein zu 1000-Seiten-Verträgen. Vielleicht: Parlamentarische Demokratie ausreichend (nationale Parlamente ratifizieren). Balance: Direkte Demokratie gut, aber zu schwierig bei komplexen Verträgen. Besser: EP stärken.', tips: 'Direkte vs. repräsentative Demokratie.' },
        { id: 'eu-19', operator: 'diskutieren', afb: 3, method: 'reflexion', question: 'Diskutieren Sie: Ist die EU ein Friedensprojekt oder eine Wirtschaftsmacht?', points: 8, sampleAnswer: 'Position Friedensprojekt: Ursprung (Montanunion) war Frieden. Kriegsunmöglichkeit. Versöhnung Deutschland-Frankreich. Friedensnobelpreis 2012. Osterweiterung festigte Frieden. Position Wirtschaftsmacht: Realität ist Binnenmarkt. Wirtschaftsinteressen dominieren. Handelspolitik zentral. Friedensrhetorik ist schön, aber Ökonomie treibt. Synthese: Beides. Friedensprojekt war Ursprung und bleibt Legitimation. Wirtschaft war Mittel und wurde Selbstzweck. Heute: Wirtschaftlich zentral, politisch-friedlich symbolisch. Spannung: Ideale vs. Interessen. EU ist beides - Frieden durch Wirtschaft. Untrennbar.', tips: 'Ideale Gründung vs. pragmatische Realität.' },
        { id: 'eu-20', operator: 'pruefen', afb: 3, method: 'reflexion', question: 'Prüfen Sie die These: "Die EU ist das erfolgreichste Friedensprojekt der Geschichte."', points: 8, sampleAnswer: 'Kriterien: Frieden, Dauer, Umfang. Pro: 70+ Jahre kein Krieg zwischen Mitgliedern. Vorher Jahrhunderte Kriege. 450 Mio. Menschen. Demokratie, Wohlstand. Friedensnobelpreis. Einzigartig. Kontra: Frieden auch durch NATO, Kalten Krieg, Atomwaffen. EU nicht alleinverantwortlich. Kriege gab es (Jugoslawien), EU versagte. Noch jung - 70 Jahre wenig historisch. Andere Beispiele: ASEAN? Prüfung: These ist übertrieben, aber berechtigt. EU trug wesentlich zu Frieden bei. Erfolgreichstes? Schwer zu messen. Aber: Sehr erfolgreich, ja. "Eines der erfolgreichsten" wäre präziser. Wichtig: Frieden ist nicht selbstverständlich - EU-Verdienst.', tips: 'Erfolg ja, Alleinverantwortung nein.' }
    ]
};

